// src/api.js
import axios from 'axios';

export const fetchLandRecords = async (query) => {
  try {
    const response = await axios.get(`http://127.0.0.1:8000/api/search/`, {
      params: { query },
    });
    return response.data;
  } catch (error) {
    console.error('Error fetching land records:', error);
  }
};
